		LL_ASSERT_DBG(0);
		break;
	}

	if (!piggy_back) {
		/* Enqueue notification towards LL, unless we reuse RX node,
		 * in which case it is handled on the ull_cp_rx return path
		 */
		ll_rx_put_sched(ntf->hdr.link, ntf);
	}


